module top(input instr_lui, instr_auipc, instr_jal, output reg decoded_imm);
    always @*
            (* parallel_case *)
            case (1'b1)
                instr_jal:
                        decoded_imm <= 1'b0;
                |{instr_lui, instr_auipc}:
                        decoded_imm <= 1'b1;
                default:
                        decoded_imm <= 1'bx;
            endcase
endmodule
